import {
  SearchBarStyle,
  SearchBarSize,
  SearchBarSpacing,
  SearchBarIcon,
  SearchBarDivider,
  SearchBarInput,
  SearchBarButton,
  DividerMargin,
  ColorConfig
} from '../viewmodel/SearchBar1Model';

@Component
struct SearchIcon {
  private styles: SearchBarStyle = new DefaultSearchBarStyle('');
  onJump?: () => void;

  build() {
    Image($r('sys.media.ohos_ic_public_scan'))
      .width(this.styles.icon.size)
      .height(this.styles.icon.size)
      .margin({ left: this.styles.spacing.iconLeft })
      .fillColor(this.styles.icon.color)
  }
}

@Component
struct SearchDivider {
  private styles: SearchBarStyle = new DefaultSearchBarStyle('');

  build() {
    Divider()
      .vertical(true)
      .height(this.styles.divider.height)
      .strokeWidth(this.styles.divider.width)
      .color(this.styles.divider.color)
      .margin({
        left: this.styles.spacing.dividerMargin.left,
        right: this.styles.spacing.dividerMargin.right
      })
  }
}

@Component
struct SearchInput {
  private styles: SearchBarStyle = new DefaultSearchBarStyle('');

  build() {
    TextInput({ placeholder: this.styles.input.placeholder })
      .placeholderColor(this.styles.input.placeholderColor)
      .placeholderFont({ size: this.styles.input.fontSize })
      .caretColor(this.styles.input.caretColor)
      .fontSize(this.styles.input.fontSize)
      .backgroundColor('transparent')
      .layoutWeight(1)
      .height(this.styles.input.height)
      .border({ width: 0 })
  }
}

@Component
struct SearchButton {
  private styles: SearchBarStyle = new DefaultSearchBarStyle('');
  onJump?: () => void;

  build() {
    Text(this.styles.button.text)
      .fontSize(this.styles.button.fontSize)
      .fontColor(this.styles.button.color)
      .backgroundColor(this.styles.button.backgroundColor)
      .borderRadius(this.styles.size.borderRadius)
      .width(this.styles.button.width)
      .height(this.styles.button.height)
      .textAlign(TextAlign.Center)
      .position({ right: this.styles.spacing.buttonRight })
      .onClick(() => this.onJump?.())
  }
}

class DefaultSearchBarStyle implements SearchBarStyle {
  readonly size: SearchBarSize;
  readonly spacing: SearchBarSpacing;
  readonly icon: SearchBarIcon;
  readonly divider: SearchBarDivider;
  readonly input: SearchBarInput;
  readonly button: SearchBarButton;
  readonly colors: ColorConfig;

  constructor(text: string) {
    this.size = {
      height: 40,
      contentHeight: 36,
      borderRadius: 24
    } as SearchBarSize;

    this.spacing = {
      horizontal: 16,
      iconLeft: 16,
      dividerMargin: {
        left: 8,
        right: 0
      } as DividerMargin,
      inputLeft: 8,
      buttonRight: 16
    } as SearchBarSpacing;

    this.icon = {
      size: 16,
      color: '#999999'
    } as SearchBarIcon;

    this.divider = {
      height: 12,
      width: 1,
      color: '#DDDDDD'
    } as SearchBarDivider;

    this.input = {
      width: 'auto',
      height: 36,
      fontSize: 16,
      placeholder: text,
      placeholderColor: '$r(\'sys.color.font_secondary\')',
      caretColor: '#0A59F7'
    } as SearchBarInput;

    this.button = {
      width: 35,
      height: this.size.height,
      fontSize: 16,
      color: '#0A59F7',
      backgroundColor: 'Color.Transparent',
      text: '搜索'
    } as SearchBarButton;

    this.colors = {
      background: 'Color.Transparent',
      contentBackground: '#0C000000',
      border: 'Color.Transparent'
    } as ColorConfig;
  }
}

@Component
export struct SearchBar1 {
  @Consume('appPathStack') appPathStack: NavPathStack;
  @State text: string = "搜索新闻/资讯/热点等";
  private styles: SearchBarStyle = new DefaultSearchBarStyle(this.text);

  jump(pageName:string = 'EmptyPagePathStack'): void {
    this.appPathStack.pushPathByName(pageName, null);
  }

  build() {
    Row() {
      Row() {
        SearchIcon({
          styles: this.styles,
          onJump: () => this.jump()
        })

        SearchDivider({ styles: this.styles })

        SearchInput({ styles: this.styles })

        SearchButton({
          styles: this.styles,
          onJump: () => this.jump()
        })
      }
      .width('100%')
      .height(this.styles.size.contentHeight)
      .backgroundColor(this.styles.colors.contentBackground)
      .borderRadius(this.styles.size.borderRadius)
      .alignItems(VerticalAlign.Center)
      .justifyContent(FlexAlign.Start)
    }
    .padding({ left: this.styles.spacing.horizontal, right: this.styles.spacing.horizontal })
    .width('100%')
    .height(this.styles.size.height)
    .backgroundColor(this.styles.colors.background)
  }
}

