export interface DividerMargin {
  left: number;
  right: number;
}

export interface ColorConfig {
  background: string;
  contentBackground: string;
  border: string;
}

export interface SearchBarSize {
  height: number;
  contentHeight: number;
  borderRadius: number;
}

export interface SearchBarSpacing {
  horizontal: number;
  iconLeft: number;
  dividerMargin: DividerMargin;
  inputLeft: number;
  buttonRight: number;
}

export interface SearchBarIcon {
  size: number;
  color: string;
}

export interface SearchBarDivider {
  height: number;
  width: number;
  color: string;
}

export interface SearchBarInput {
  width: string;
  height: number;
  fontSize: number;
  placeholder: string;
  placeholderColor: string;
  caretColor: string;
}

export interface SearchBarButton {
  width: number;
  height: number;
  fontSize: number;
  color: string;
  backgroundColor: string;
  text: string;
  paddingVertical: number;
}

export interface SearchBarStyle {
  size: SearchBarSize;
  spacing: SearchBarSpacing;
  icon: SearchBarIcon;
  divider: SearchBarDivider;
  input: SearchBarInput;
  button: SearchBarButton;
  colors: ColorConfig;
}

export class DefaultSearchBarStyle implements SearchBarStyle {
  readonly size: SearchBarSize;
  readonly spacing: SearchBarSpacing;
  readonly icon: SearchBarIcon;
  readonly divider: SearchBarDivider;
  readonly input: SearchBarInput;
  readonly button: SearchBarButton;
  readonly colors: ColorConfig;

  constructor() {
    this.size = {
      height: 48,
      contentHeight: 36,
      borderRadius: 18
    } as SearchBarSize;

    this.spacing = {
      horizontal: 16,
      iconLeft: 12,
      dividerMargin: {
        left: 8,
        right: 0
      } as DividerMargin,
      inputLeft: 8,
      buttonRight: 1
    } as SearchBarSpacing;

    this.icon = {
      size: 16,
      color: '#999999'
    } as SearchBarIcon;

    this.divider = {
      height: 14,
      width: 1,
      color: '#DDDDDD'
    } as SearchBarDivider;

    this.input = {
      width: '60%',
      height: 36,
      fontSize: 14,
      placeholder: '一点点｜味千拉面',
      placeholderColor: '#333333',
      caretColor: '#0099FF'
    } as SearchBarInput;

    this.button = {
      width: 64,
      height: 32,
      fontSize: 14,
      color: '#FFFFFF',
      backgroundColor: '#0099FF',
      text: '搜索',
      paddingVertical: 6
    } as SearchBarButton;

    this.colors = {
      background: '#FFFFFF',
      contentBackground: '#F5F5F5',
      border: '#0099FF'
    } as ColorConfig;
  }
}

