import { SearchBarStyle, SearchBar2Model } from '../viewmodel/SearchBar2Model';

@Component
struct LocationSection {
  @Consume('appPathStack') appPathStack: NavPathStack;
  @Prop styles: SearchBarStyle;
  onJump?: () => void;

  build() {
    Row() {
      Text('杭州')
        .fontSize(this.styles.base.fontSize)
        .fontWeight(FontWeight.Medium)
        .fontColor(this.styles.colors.text)
        .onClick(() => this.appPathStack.pushPathByName('Page_ScreenList', null))
      Image($r('app.media.ic_public_search'))
        .width(this.styles.location.iconWidth)
        .height(this.styles.location.iconHeight)
        .margin({ left: this.styles.location.iconMargin })
        .fillColor(this.styles.colors.text)
        .onClick(() => this.onJump?.())
    }
    .height(this.styles.location.height)
    .alignItems(VerticalAlign.Center)
    .margin({ right: this.styles.location.iconMargin * 4 })
  }
}

@Component
struct SearchSection {
  @Prop styles: SearchBarStyle;
  @State text: string = "武林广场夜市";
  onJump?: () => void;

  build() {
    Row() {
      Image($r('sys.media.ohos_ic_public_scan'))
        .width(this.styles.search.iconWidth)
        .height(this.styles.search.iconHeight)
        .margin({ left: this.styles.search.iconMargin })
        .fillColor(this.styles.colors.icon)

      Divider()
        .vertical(true)
        .height(this.styles.search.dividerHeight)
        .strokeWidth(this.styles.search.dividerWidth)
        .color(this.styles.colors.divider)
        .margin({
          left: this.styles.search.dividerMarginLeft,
          right: this.styles.search.dividerMarginRight
        })

      TextInput({ placeholder: this.text })
        .placeholderColor(this.styles.colors.placeholder)
        .placeholderFont({ size: this.styles.base.fontSize })
        .caretColor(this.styles.colors.primary)
        .fontSize(this.styles.base.fontSize)
        .backgroundColor('transparent')
        .width(this.styles.search.inputWidth)
        .height(this.styles.search.inputHeight)
        .border({ width: 0 })
        .padding({ left: this.styles.search.inputPaddingLeft })

      Row() {
        Text('搜索')
          .fontSize(this.styles.base.fontSize)
          .fontColor(this.styles.colors.fontColor)
          .onClick(() => this.onJump?.())
      }
      .backgroundColor(this.styles.colors.primary)
      .borderRadius(this.styles.base.borderRadius)
      .width(this.styles.search.buttonWidth)
      .height(this.styles.search.buttonHeight)
      .margin({ right: this.styles.search.buttonMargin })
      .justifyContent(FlexAlign.Center)
      .alignItems(VerticalAlign.Center)
    }
    .width(this.styles.search.width)
    .height(this.styles.search.height)
    .backgroundColor(this.styles.colors.background)
    .borderRadius(this.styles.base.borderRadius)
    .alignItems(VerticalAlign.Center)
    .justifyContent(FlexAlign.SpaceBetween)
  }
}

@Component
struct ActionSection {
  @Prop styles: SearchBarStyle;
  @State icon: Resource = $r('app.media.startIcon');
  onJump?: () => void;

  build() {
    Row({ space: this.styles.action.space }) {
      Image(this.icon)
        .width(this.styles.action.iconWidth)
        .height(this.styles.action.iconHeight)
        .fillColor(this.styles.colors.text)
        .margin({ left: this.styles.action.iconMarginLeft })
        .onClick(() => this.onJump?.())

      Image($r('app.media.ic_more'))
        .width(this.styles.action.iconWidth)
        .height(this.styles.action.iconHeight)
        .fillColor(this.styles.colors.text)
        .margin({
          left: this.styles.action.iconMarginLeft,
          right: this.styles.action.iconMarginRight
        })
        .onClick(() => this.onJump?.())
    }
    .height(this.styles.action.height)
    .alignItems(VerticalAlign.Center)
  }
}

@Component
export struct SearchBar2 {
  @Consume('appPathStack') appPathStack: NavPathStack;
  @State private model: SearchBar2Model = new SearchBar2Model();
  @State text: string = "武林广场夜市";
  @State icon: Resource = $r('app.media.startIcon');

  jump(pageName:string = 'EmptyPagePathStack'): void {
    this.appPathStack.pushPathByName(pageName, null);
  }

  build() {
    Row() {
      LocationSection({
        styles: this.model.styles,
        onJump: () => this.jump()
      })

      SearchSection({
        styles: this.model.styles,
        text: this.text,
        onJump: () => this.jump()
      })

      ActionSection({
        styles: this.model.styles,
        icon: this.icon,
        onJump: () => this.jump()
      })
    }
    .width('100%')
    .padding({
      left: this.model.styles.base.paddingLeft,
      right: this.model.styles.base.paddingRight
    })
    .height(this.model.styles.base.height)
    .backgroundColor(Color.Transparent)
    .justifyContent(FlexAlign.SpaceBetween)
    .alignItems(VerticalAlign.Center)
  }
}

