  height: number = 32;
  iconWidth: number = 12;
  iconHeight: number = 12;
  iconMargin: number = 2;
}

export class SearchInputStyle {
  width: string = '65%';
  height: number = 32;
  iconWidth: number = 16;
  iconHeight: number = 16;
  iconMargin: number = 8;
  dividerHeight: number = 14;
  dividerWidth: number = 1;
  dividerMarginLeft: number = 8;
  dividerMarginRight: number = 0;
  inputWidth: string = '60%';
  inputHeight: number = 32;
  inputPaddingLeft: number = 6;
  buttonWidth: number = 43;
  buttonHeight: number = 28;
  buttonMargin: number = 2;
}

export class ActionStyle {
  height: number = 32;
  space: number = 4;
  iconWidth: number = 20;
  iconHeight: number = 20;
  iconMarginLeft: number = 8;
  iconMarginRight: number = 4;
}

export class BaseStyle {
  height: number = 44;
  fontSize: number = 14;
  borderRadius: number = 16;
  paddingLeft: number = 16;
  paddingRight: number = 16;
}

export class ColorStyle {
  primary: string = 'Color.Transparent';
  text: string = '#333333';
  placeholder: string = '$r(\'sys.color.font_secondary\')';
  icon: string = '#999999';
  divider: string = '#DDDDDD';
  background: string = '#0C000000';
  fontColor: string = '#0A59F7';
}

export class SearchBarStyle {
  base: BaseStyle;
  colors: ColorStyle;
  location: LocationStyle;
  search: SearchInputStyle;
  action: ActionStyle;

  constructor() {
    this.base = new BaseStyle();
    this.colors = new ColorStyle();
    this.location = new LocationStyle();
    this.search = new SearchInputStyle();
    this.action = new ActionStyle();
  }
}

export class SearchBar2Model {
  styles: SearchBarStyle;

  constructor() {
    this.styles = new SearchBarStyle();
  }
}

