                logo: item.getLogo(),
                title: item.getTitle(),
                bookSituation: item.getBookSituation(),
                hotelName: item.getHotelName(),
                beginTime: item.getBeginTime(),
                duration: item.getDuration(),
                endTime: item.getEndTime(),
                room: item.getRoom(),
                NAVIGATION: item.getNAVIGATION(),
                BUTTON_DETAIL: item.getBUTTON_DETAIL(),
                BUTTON_SHARE: item.getBUTTON_SHARE()
