import LazyDataSource from '../util/LazyDataSource';
import {
  VerticalGraphicOrderItem2Model,
  WaterFlow_VerticalGraphicOrderItem2Model
} from '../viewmodel/WaterFlow_VerticalGraphicOrderItem2Model';

@Component
export struct WaterFlow_VerticalGraphicOrderItem2 {
  @State itemModel: WaterFlow_VerticalGraphicOrderItem2Model =
    WaterFlow_VerticalGraphicOrderItem2Model.getInstance();
  @State lazyDataSource: LazyDataSource<VerticalGraphicOrderItem2Model> =
    this.itemModel.lazyDataSource;
  @State moduleTitle: string = "模块名";
  @State moduleRedirectContent: string = "跳转";
  @State loadingStatus: LoadingStatus = LoadingStatus.OFF;
  @Consume('appPathStack') appPathStack: NavPathStack;
  @StorageLink('currentWidthBreakpoint') currentWidthBreakpoint: string = BreakpointConstants.BREAKPOINT_SM;

  jump(pageName:string = 'EmptyPagePathStack'): void {
    this.appPathStack.pushPathByName(pageName, null);
  }

  aboutToAppear() {
    this.loadResources();

  }

  loadResources(): void {
    this.loadingStatus = LoadingStatus.LOADING;
    this.itemModel.getResources().then(() => {
      this.loadingStatus = LoadingStatus.SUCCESS;
    }).catch(() => {
      this.loadingStatus = LoadingStatus.FAILED;
    });
  }

  build() {
    Column() {
      Column() {
        ModuleTitleComponent({
				title: this.moduleTitle,
				moduleRedirectContent: this.moduleRedirectContent,
				onJump: () => {
				  this.jump()
				}})

        if (this.loadingStatus === LoadingStatus.FAILED) {
          LoadingFailedView(() => this.loadResources())
        } else if (this.loadingStatus === LoadingStatus.SUCCESS) {
          WaterFlow() {
            LazyForEach(this.lazyDataSource, (item: VerticalGraphicOrderItem2Model, index: number) => {
              FlowItem() {
                VerticalGraphicOrderItem2({
                  icon: item.getIcon(),
                  shop_name: item.getShopName(),
                  situation: item.getSituation(),
                  good_img: item.getGoodImg(),
                  good_name: item.getGoodName(),
                  good_detail: item.getGoodDetail(),
                  price: item.getPrice(),
                  tags: item.getTags(),
                  nums: item.getNums(),
                  real_price: item.getRealPrice(),
                  buttons: item.getButtons()
                })
              }
              .onClick(() => {
                this.jump("WaterFlow_VerticalGraphicOrderItem2Detail"+index.toString())
              })
              .height(200)
              .width(CommonConstants.FULL_PERCENT)
            }, (item: VerticalGraphicOrderItem2Model, index: number) => index + JSON.stringify(item))
          }
          .nestedScroll({ scrollForward: NestedScrollMode.PARENT_FIRST, scrollBackward: NestedScrollMode.SELF_FIRST })
          .cachedCount(4)
          .columnsTemplate("1fr")
          .columnsGap("6vp")
          .rowsGap("12vp")
          .width(CommonConstants.FULL_PERCENT)
        }
      }
      .width('92%')
    }
    .width('100%')
    .margin({ bottom: "10vp" })
  }
}

