            .fontWeight(500)
          Text(this.nums)
            .fontSize(10)
            .fontColor(Color.Gray)
            .padding({ top: 4 })
        }
        .width('20%')
        .height(CommonConstants.FULL_PERCENT)
        .alignItems(HorizontalAlign.End)
      }
      .width(CommonConstants.FULL_PERCENT)
      .height('50%')
      .padding({ top: 10 })

      Row() {
        Text("实付款")
          .fontSize(12)
          .fontWeight(500)
        Text(this.real_price)
          .fontSize(16)
          .fontWeight(500)
      }
      .width(CommonConstants.FULL_PERCENT)
      .height('20%')
      .justifyContent(FlexAlign.End)
      .alignItems(VerticalAlign.Bottom)
      .padding({ top: 6 })

      Row() {
        Text("更多")
          .fontSize(12)
          .fontColor(Color.Gray)
