  lazyDataSource: LazyDataSource<SimpleOrderInformationDisplayModel> = new LazyDataSource();
  static readonly PRICES: string[] = ['¥ 319'];
  static readonly TITLES: string[] = ['江北天街店'];
  static readonly ORDER_STATUS: string[] = ['已完成'];
  static readonly ORDER_TIMES: string[] = ['2024-05-25 20:52:30'];

  constructor() {
  }

  public static getInstance(): Tab_List_OrderListModel {
    if (!Tab_List_OrderListModel.instance) {
      Tab_List_OrderListModel.instance =
        new Tab_List_OrderListModel();
    }
    return Tab_List_OrderListModel.instance;
  }

  /**
   * Data loaded on current view converts network data into rendering data
   */
  getResources(): Promise<void> {

    /**
     * use your web request here
     */
    return new Promise((resolve: Function) => {
      const modelList: Array<SimpleOrderInformationDisplayModel> = [];
      for (let index = 0; index < Tab_List_OrderListModel.PRICES.length;
        index++) {
        modelList.push(new SimpleOrderInformationDisplayModel(
          Tab_List_OrderListModel.PRICES[index],
          Tab_List_OrderListModel.TITLES[index],
          Tab_List_OrderListModel.ORDER_STATUS[index],
          Tab_List_OrderListModel.ORDER_TIMES[index]));
      }
      this.lazyDataSource.pushArrayData(modelList);
      resolve();
    });
  }
}

