@Component
export struct List_H_PureImageItem {
  @State itemModel: List_H_PureImageItemModel =
    List_H_PureImageItemModel.getInstance();
  @Prop listDirection: Axis = Axis.Horizontal
  @State moduleTitle: string = "模块名";
  @State moduleRedirectContent: string = "跳转";
  @State loadingStatus: LoadingStatus = LoadingStatus.OFF;
  @State lazyDataSource: LazyDataSource<PureImageItemModel> =
    this.itemModel.lazyDataSource;
  private spaceArray: string[] = ['6vp', '16vp', '20vp'];
  @Consume('appPathStack') appPathStack: NavPathStack;
  @StorageLink('currentWidthBreakpoint') currentWidthBreakpoint: string = BreakpointConstants.BREAKPOINT_SM;

  aboutToAppear() {
    this.loadResources();

  }
  jump(pageName:string = 'EmptyPagePathStack'): void {
    this.appPathStack.pushPathByName(pageName, null);
  }


  loadResources(): void {
    this.loadingStatus = LoadingStatus.LOADING;
    this.itemModel.getResources().then(() => {
      this.loadingStatus = LoadingStatus.SUCCESS;
    }).catch(() => {
      this.loadingStatus = LoadingStatus.FAILED;
    });
  }

  build() {
    Column() {
      ModuleTitleComponent({
				title: this.moduleTitle,
				moduleRedirectContent: this.moduleRedirectContent,
				onJump: () => {
				  this.jump()
				}})
        .width('92%')

      if (this.loadingStatus === LoadingStatus.FAILED) {
        LoadingFailedView(() => this.loadResources())
      }
      if (this.loadingStatus === LoadingStatus.SUCCESS) {
        List({
          space: new BreakpointType(this.spaceArray[0], this.spaceArray[1],
            this.spaceArray[2]).getValue(this.currentWidthBreakpoint)
        }) {
          LazyForEach(this.lazyDataSource, (item: PureImageItemModel, index: number) => {
            ListItem() {
              PureImageItem({
                image: item.getImage()
              })
            }
            .width('120vp')
            .height('150vp')
            .onClick(() => {
              this.jump("List_H_PureImageItemDetail"+index.toString())
            })
          }, (item: PureImageItemModel, index: number) => index + JSON.stringify(item))
        }
        .width('92%')
        .height('auto')
        .listDirection(this.listDirection)
        .edgeEffect(EdgeEffect.Spring, {alwaysEnabled: true})
      }
    }
    .width('100%')
    .margin({ bottom: "10vp" })
  }
}
