import { LoadingStatus } from '../common/CommonEnums';
import { LoadingFailedView } from '../view/LoadingFailedView'
import { ModuleTitleComponent } from '../common/ModuleTitleComponent';
import { BreakpointConstants } from '../common/BreakpointConstants';
import { CommonConstants } from '../common/CommonConstants';
import { BreakpointType } from '../util/BreakpointType';
import LazyDataSource from '../util/LazyDataSource';
import {
  VerticalTextButtonImageItemModel,
  WaterFlow_VerticalTextButtonImageItemModel } from '../viewmodel/WaterFlow_VerticalTextButtonImageItemModel';

@Component
export struct WaterFlow_VerticalTextButtonImageItem {
  @State itemModel: WaterFlow_VerticalTextButtonImageItemModel =
    WaterFlow_VerticalTextButtonImageItemModel.getInstance();
  @State lazyDataSource: LazyDataSource<VerticalTextButtonImageItemModel> =
    this.itemModel.lazyDataSource;
  @State moduleTitle: string = "模块名";
  @State moduleRedirectContent: string = "跳转";
  @State loadingStatus: LoadingStatus = LoadingStatus.OFF;
  @Consume('appPathStack') appPathStack: NavPathStack;
  @StorageLink('currentWidthBreakpoint') currentWidthBreakpoint: string = BreakpointConstants.BREAKPOINT_SM;
  private columnNumberArray: number[] = [2, 4, 4];

  aboutToAppear() {
    this.loadResources();

  }
  jump(pageName:string = 'EmptyPagePathStack'): void {
    this.appPathStack.pushPathByName(pageName, null);
  }


  loadResources(): void {
    this.loadingStatus = LoadingStatus.LOADING;
    this.itemModel.getResources().then(() => {
      this.loadingStatus = LoadingStatus.SUCCESS;
    }).catch(() => {
      this.loadingStatus = LoadingStatus.FAILED;
    });
  }

  build() {
    Column() {
      ModuleTitleComponent({
				title: this.moduleTitle,
				moduleRedirectContent: this.moduleRedirectContent,
				onJump: () => {
				  this.jump()
				}})

      if (this.loadingStatus === LoadingStatus.FAILED) {
        LoadingFailedView(() => this.loadResources())
      } else if (this.loadingStatus === LoadingStatus.SUCCESS) {
        WaterFlow() {
          LazyForEach(this.lazyDataSource, (item: VerticalTextButtonImageItemModel, index: number) => {
            FlowItem() {
              VerticalTextButtonImageItem({
                title: item.getTitle(),
                detail: item.getDetail(),
                buttonValue: item.getButtonValue(),
                image: item.getImage()
              })
            }
            .onClick(() => {
              this.jump("WaterFlow_VerticalTextButtonImageItemDetail"+index.toString())
            })
            .width(CommonConstants.FULL_PERCENT)
            .height('120vp')
          }, (item: VerticalTextButtonImageItemModel, index: number) => index + JSON.stringify(item))
        }
        .nestedScroll({ scrollForward: NestedScrollMode.PARENT_FIRST, scrollBackward: NestedScrollMode.SELF_FIRST })
        .cachedCount(4)
        .columnsTemplate(("1fr ").repeat(new BreakpointType(this.columnNumberArray[0], this.columnNumberArray[1],
          this.columnNumberArray[2]).getValue(this.currentWidthBreakpoint)).trim())
        .columnsGap("8vp")
        .rowsGap("8vp")
        .width(CommonConstants.FULL_PERCENT)
      }
    }
    .width('92%')
    .borderRadius($r('sys.float.corner_radius_level8'))
    .margin({ bottom: "10vp" })
  }
}

@Component
export struct VerticalTextButtonImageItem {
  @State title:string = '积分权益'
  @State detail:string = '购票领畅行积分'
  @State buttonValue:string = '去查看>'
  @State image:Resource = $r('app.media.random_background_3')
  @Consume('appPathStack') appPathStack: NavPathStack;
  jump(pageName:string = 'EmptyPagePathStack'): void {
    this.appPathStack.pushPathByName(pageName, null);
  }


  build() {
    Column(){
      Column(){
        Text(this.title)
          .fontSize($r('app.integer.subtitle_text_S'))
          .fontWeight(FontWeight.Medium)
          .fontColor($r('app.color.font_on_primary'))
        Text(this.detail)
          .fontSize($r('app.integer.body_text_S'))
          .fontWeight(FontWeight.Regular)
          .fontColor($r('app.color.font_on_secondary'))
          .margin({top:2})
      }
      .alignItems(HorizontalAlign.Start)
      Button(this.buttonValue)
        .type(ButtonType.Capsule)
        .controlSize(ControlSize.SMALL)
        .fontColor($r('app.color.font_on_primary'))
        .backgroundColor($r('app.color.comp_background_emphasize'))
        .onClick(() => {
          this.jump()
        })
    }
    .width(CommonConstants.FULL_PERCENT)
    .height(CommonConstants.FULL_PERCENT)
    .justifyContent(FlexAlign.SpaceBetween)
    .alignItems(HorizontalAlign.Start)
    .padding(8)
    .backgroundImage(this.image)
    .backgroundImageSize(ImageSize.Cover)
    .borderRadius($r('sys.float.corner_radius_level4'))
  }
}

