@Component
export struct Tab_List_HorizontalComplexGraphicTextDisplayItem {
  @State titles: string[] = ['推荐', '附近', '公寓', '业主自荐'];
  @State currentIndex: number = 0;
  private tabsController: TabsController = new TabsController();
  @State selectContents: string[] = ['全部', '精装修', '押一付一', '舒适两居', '房东直租'];
  @State isSelected: boolean[] = [];
  @State model: Tab_List_HorizontalComplexGraphicTextDisplayItemModel =
    new Tab_List_HorizontalComplexGraphicTextDisplayItemModel();

  aboutToAppear(): void {
    for (let index = 0; index < this.selectContents.length; index++) {
      if (index === 0) {
        this.isSelected.push(true)
      } else {
        this.isSelected.push(false)
      }
    }
  }

  @Builder
  TabBuilder(index: number, title: string) {
    Column() {
      Text(title)
        .width(CommonConstants.FULL_PERCENT)
        .fontSize($r('app.integer.subtitle_text_S'))
        .fontColor(this.currentIndex === index ? $r('app.color.font_primary') : $r('app.color.font_secondary'))
        .fontWeight(this.currentIndex === index ? FontWeight.Bold : FontWeight.Medium)
        .textAlign(TextAlign.Center)
      if (this.currentIndex === index) {
        Line()
          .width('30%')
          .height(2)
          .borderRadius($r('sys.float.corner_radius_level4'))
          .backgroundColor('#D08F88')
      }
    }
    .width(CommonConstants.FULL_PERCENT)
    .height(CommonConstants.FULL_PERCENT)
    .justifyContent(FlexAlign.SpaceBetween)
  }

  @Builder
  SelectItem(content: string, index: number) {
    Text(content)
      .fontSize($r('app.integer.caption_text_M'))
      .fontWeight(this.isSelected[index] === false ? FontWeight.Medium : FontWeight.Bold)
      .fontColor(this.isSelected[index] === false ? $r('app.color.font_secondary') : '#EB9D90')
      .borderRadius($r('sys.float.corner_radius_level1'))
      .backgroundColor(this.isSelected[index] === false ? '#F5F8F5' : '#FFEFEC')
      .padding(6)
      .margin({ left: 4, right: 4 })
      .onClick(() => {
        this.isSelected[index] = !this.isSelected[index]
      })
  }

  @Builder
  SelectRow() {
    Row() {
      ForEach(this.selectContents, (content: string, index: number) => {
        this.SelectItem(content, index)
      })
    }
    .width(CommonConstants.FULL_PERCENT)
    .height(40)
    .padding({ left: 12 })
  }

  build() {
    Column() {
      Tabs() {
        TabContent() {
          Column() {
            this.SelectRow()
            List_HorizontalComplexGraphicTextDisplayItem1({ model: $model })
          }
        }
        .tabBar(this.TabBuilder(0, this.titles[0]))


        TabContent() {
          Column() {
            this.SelectRow()
            List_HorizontalComplexGraphicTextDisplayItem2({ model: $model })
          }
        }
        .tabBar(this.TabBuilder(1, this.titles[1]))

        TabContent() {
          Column() {
            this.SelectRow()
            List_HorizontalComplexGraphicTextDisplayItem3({ model: $model })
          }
        }
        .tabBar(this.TabBuilder(2, this.titles[2]))

        TabContent() {
          Column() {
            this.SelectRow()
            List_HorizontalComplexGraphicTextDisplayItem4({ model: $model })
          }
        }
        .tabBar(this.TabBuilder(3, this.titles[3]))

        TabContent() {

        }
        .tabBar(this.TabBuilder(4, ''))
      }
      .width('auto')
      .height('auto')
      .scrollable(true)
      .barPosition(BarPosition.Start)
      .vertical(false)
      .barWidth(CommonConstants.FULL_PERCENT)
      .barHeight(20)
      .borderRadius($r('sys.float.corner_radius_level8'))
      .onChange((index: number) => {
        this.currentIndex = index
      })
    }
    .width('92%')
    .borderRadius($r('sys.float.corner_radius_level8'))
    .backgroundColor($r('app.color.comp_background_primary_trans'))
    .padding({ top: 12 })
    .margin({ bottom: "10vp" })
  }
}

