import { LoadingStatus } from '../common/CommonEnums';
import { LoadingFailedView } from '../view/LoadingFailedView';
import { BreakpointConstants } from '../common/BreakpointConstants';
import { BreakpointType } from '../util/BreakpointType';
import LazyDataSource from '../util/LazyDataSource';
import { CommonConstants } from '../common/CommonConstants';
import {
  HorizontalRankingItemModel,
  Tab_List_HorizontalRankingItemModel
} from '../viewmodel/Tab_List_HorizontalRankingItemModel';


@Component
export struct Tab_List_HorizontalRankingItem {
  @State titles: string[] = ['热播榜', '口碑榜', '新品榜'];
  @State currentIndex: number = 0
  private tabsController: TabsController = new TabsController()

  @Builder
  TabBuilder(index: number, title: string) {
    Column() {
      Text(title)
        .width(CommonConstants.FULL_PERCENT)
        .fontSize($r('app.integer.subtitle_text_S'))
        .fontColor(this.currentIndex === index ? $r('app.color.font_primary') : $r('app.color.font_secondary'))
        .fontWeight(this.currentIndex === index ? FontWeight.Bold : FontWeight.Medium)
        .textAlign(TextAlign.Center)
        .padding({ bottom: 2 })
      if (this.currentIndex === index) {
        Line()
          .width('10%')
          .height(2)
          .borderRadius($r('sys.float.corner_radius_level4'))
          .backgroundColor('#CC624C')
      }
    }
    .width(CommonConstants.FULL_PERCENT)
    .height(CommonConstants.FULL_PERCENT)
    .alignItems(HorizontalAlign.Center)
    .justifyContent(FlexAlign.Center)
  }

  build() {
    Column() {
      Tabs() {
        TabContent() {
          List_HorizontalRankingItem()
        }
        .tabBar(this.TabBuilder(0, this.titles[0]))

        TabContent() {
          List_HorizontalRankingItem()
        }
        .tabBar(this.TabBuilder(1, this.titles[1]))

        TabContent() {
          List_HorizontalRankingItem()
        }
        .tabBar(this.TabBuilder(2, this.titles[2]))

        TabContent() {
        }
        .tabBar(this.TabBuilder(3, this.titles[3]))
      }
      .width('auto')
      .height('auto')
      .scrollable(true)
      .barPosition(BarPosition.Start)
      .vertical(false)
      .barWidth(CommonConstants.FULL_PERCENT)
      .barHeight(40)
      .borderRadius($r('sys.float.corner_radius_level8'))
      .onChange((index: number) => {
        this.currentIndex = index
      })
    }
    .width(CommonConstants.FULL_PERCENT)
    .borderRadius($r('sys.float.corner_radius_level8'))
    .margin({ bottom: "10vp" })
  }
}

@Component
export struct List_HorizontalRankingItem {
  @State itemModel: Tab_List_HorizontalRankingItemModel =
    Tab_List_HorizontalRankingItemModel.getInstance();
  @Prop listDirection: Axis = Axis.Vertical
  @State loadingStatus: LoadingStatus = LoadingStatus.OFF;
  @State lazyDataSource1: LazyDataSource<HorizontalRankingItemModel> =
    this.itemModel.lazyDataSource;
  private spaceArray: string[] = ['0vp', '16vp', '20vp'];
  private lanesArray: number[] = [1, 3, 4];
  @Consume('appPathStack') appPathStack: NavPathStack;
  @StorageLink('currentWidthBreakpoint') currentWidthBreakpoint: string = BreakpointConstants.BREAKPOINT_SM;

  jump(pageName:string = 'EmptyPagePathStack'): void {
    this.appPathStack.pushPathByName(pageName, null);
  }

  aboutToAppear() {
    this.loadResources();

  }

  loadResources(): void {
    this.loadingStatus = LoadingStatus.LOADING;
    this.itemModel.getResources().then(() => {
      this.loadingStatus = LoadingStatus.SUCCESS;
    }).catch(() => {
      this.loadingStatus = LoadingStatus.FAILED;
    });
  }

  build() {
    Column() {
      if (this.loadingStatus === LoadingStatus.FAILED) {
        LoadingFailedView(() => this.loadResources())
      }
      if (this.loadingStatus === LoadingStatus.SUCCESS) {
        List({
          space: new BreakpointType(this.spaceArray[0], this.spaceArray[1],
            this.spaceArray[2]).getValue(this.currentWidthBreakpoint)
        }) {
          LazyForEach(this.lazyDataSource1, (item: HorizontalRankingItemModel, index: number) => {
            ListItem() {
              HorizontalRankingItem({
                title: item.getTitle(),
                contentIcon: item.getContentIcon(),
                content: item.getContent(),
                image: item.getImage(),
                index: item.getIndex()
              })
            }
            .height(50)
            .backgroundColor($r('app.color.comp_background_gray'))
            .onClick(() => {
              this.jump("List_HorizontalRankingItemDetail"+index.toString())
            })
          }, (item: HorizontalRankingItemModel, index: number) => index + JSON.stringify(item))
        }
        .width('92%')
        .height('auto')
        .listDirection(this.listDirection)
        .edgeEffect(EdgeEffect.Spring, {alwaysEnabled: true})
        .lanes(new BreakpointType(this.lanesArray[0], this.lanesArray[1],
          this.lanesArray[2]).getValue(this.currentWidthBreakpoint), "12vp")
        .backgroundColor($r('app.color.comp_background_primary_trans'))
        .borderRadius($r('sys.float.corner_radius_level4'))

        Text('查看更多 >')
          .fontSize($r('app.integer.caption_text_M'))
          .fontWeight(FontWeight.Medium)
          .fontColor($r('app.color.font_secondary'))
          .padding({ bottom: 8 })
      }
    }
    .width('92%')
    .backgroundColor($r('app.color.comp_background_primary_trans'))
    .borderRadius($r('sys.float.corner_radius_level4'))
  }
}

@Component
export struct HorizontalRankingItem {
  @State title: string = '公安部网安局提醒防范职业窃密'
  @State contentIcon: Resource = $r('app.media.icon')
  @State content: string = '999万+'
  @State image: Resource = $r('app.media.icon')
  @State index: number = 0
  @State currentColors: string[] = ['#D66444', '#C36A24', '#E2C65C', '#8F8F8F']

  build() {
    Row() {
      Row() {
        Text(`${this.index + 1}`)
          .fontSize($r('app.integer.subtitle_text_L'))
          .fontWeight(FontWeight.Bold)
          .fontColor(this.index < 4 ? this.currentColors[this.index] : this.currentColors[3])

        Column({ space: 4 }) {
          Text(this.title)
            .width(CommonConstants.FULL_PERCENT)
            .fontSize($r('app.integer.body_text_S'))
            .fontWeight(FontWeight.Medium)
            .fontColor($r('app.color.font_primary'))
            .maxLines(1)
            .textOverflow({ overflow: TextOverflow.Ellipsis })
            .padding({ top: 3 })
          Row({ space: 4 }) {
            Image(this.contentIcon)
              .height('18%')
              .fillColor($r('app.color.font_tertiary'))
            Text(this.content)
              .width(CommonConstants.FULL_PERCENT)
              .fontSize($r('app.integer.caption_text_S'))
              .fontWeight(FontWeight.Regular)
              .fontColor($r('app.color.font_tertiary'))
              .maxLines(1)
              .textOverflow({ overflow: TextOverflow.Ellipsis })
          }
          .width(CommonConstants.FULL_PERCENT)
        }
        .width('90%')
        .height(CommonConstants.FULL_PERCENT)
        .padding({ left: 8 })
      }
      .width('80%')
      .height(CommonConstants.FULL_PERCENT)
      .alignItems(VerticalAlign.Top)

      Image(this.image)
        .width('15%')
        .height('80%')
        .borderRadius($r('sys.float.corner_radius_level2'))
    }
    .width(CommonConstants.FULL_PERCENT)
    .justifyContent(FlexAlign.SpaceBetween)
    .alignItems(VerticalAlign.Top)
    .padding({
      left: 4,
      right: 4,
      top: 12,
      bottom: 8
    })
    .backgroundColor($r('app.color.comp_background_primary_trans'))
  }
}

