  static readonly CONTENT_ICONS: Resource[] =
    [$r('app.media.ic_public_app'), $r('app.media.ic_public_app'), $r('app.media.ic_public_app'),
        $r('app.media.ic_public_app')];
  static readonly CONTENTS: string[] =
    ['999万+', '999万+', '999万+', '999万+'];
  static readonly IMAGES: Resource[] =
    [$r('app.media.icon'), $r('app.media.icon'), $r('app.media.icon'),
        $r('app.media.icon')];
  static readonly INDEX: number[] = [];

  constructor() {
  }

  public static createIndex(): void {
    for (let i = 0; i < Tab_List_HorizontalRankingItemModel.TITLES.length; i++) {
      Tab_List_HorizontalRankingItemModel.INDEX.push(i)
    }
  }

  public static getInstance(): Tab_List_HorizontalRankingItemModel {
    if (!Tab_List_HorizontalRankingItemModel.instance) {
      Tab_List_HorizontalRankingItemModel.instance =
        new Tab_List_HorizontalRankingItemModel();
    }
    return Tab_List_HorizontalRankingItemModel.instance;
  }

  /**
   * Data loaded on current view converts network data into rendering data
   */
  getResources(): Promise<void> {

    Tab_List_HorizontalRankingItemModel.createIndex()
    /**
     * use your web request here
     */
    return new Promise((resolve: Function) => {
      const modelList: Array<HorizontalRankingItemModel> = [];
      for (let index = 0; index < Tab_List_HorizontalRankingItemModel.IMAGES.length;
        index++) {
        modelList.push(new HorizontalRankingItemModel(
          Tab_List_HorizontalRankingItemModel.TITLES[index],
          Tab_List_HorizontalRankingItemModel.CONTENT_ICONS[index],
          Tab_List_HorizontalRankingItemModel.CONTENTS[index],
          Tab_List_HorizontalRankingItemModel.IMAGES[index],
          Tab_List_HorizontalRankingItemModel.INDEX[index]));
      }
      this.lazyDataSource.pushArrayData(modelList);
      resolve();
    });
  }
}

export class HorizontalRankingItemModel {
  private title: string;
