import { FoodListModel, FoodItem } from '../viewmodel/FoodListModel'
import LazyDataSource from '../util/LazyDataSource';
import { LoadingStatus } from '../common/CommonEnums';
import { LoadingFailedView } from '../view/LoadingFailedView';

@Component
export struct FoodList {
  @State foodListModel: FoodListModel = FoodListModel.getInstance();
  @State loadingStatus: LoadingStatus = LoadingStatus.OFF;
  @State lazyDataSource: LazyDataSource<FoodItem> =
    this.foodListModel.lazyDataSource;

  aboutToAppear() {
    this.loadResources();
  }

  loadResources(): void {
    this.loadingStatus = LoadingStatus.LOADING;
    this.foodListModel.getResources().then(() => {
      this.loadingStatus = LoadingStatus.SUCCESS;
    }).catch(() => {
      this.loadingStatus = LoadingStatus.FAILED;
    });
  }

  build() {
    Column() {
      if (this.loadingStatus === LoadingStatus.FAILED) {
        LoadingFailedView(() => this.loadResources())
      }
      if (this.loadingStatus === LoadingStatus.SUCCESS) {
      Column() {
        WaterFlow() {
          LazyForEach(this.lazyDataSource, (item: FoodItem) => {
            FlowItem() {
              Column() {
                Stack({ alignContent: Alignment.BottomStart }) {
                  Image(item.getImg())
                    .height(160)
                    .width('100%')
                    .borderRadius(8)
                  Row() {
                    Image($r('app.media.icon'))
                      .height(20)
                      .width(20)
                      .margin({ right: 4 })
                    Text(item.getTime() + '分钟 ' + item.getDistance() + 'km')
                      .fontColor('#ffffffff')
                      .fontSize(10)
                  }
                  .backgroundColor('#7c000000')
                  .padding({ right: 4 })
                  .borderRadius(4)
                  .margin({ left: 8, bottom: 8 })
                }

                Text(item.getName())
                  .fontSize(14)
                  .textOverflow({ overflow: TextOverflow.Ellipsis })
                  .maxLines(2)
                  .padding(4)
                Row() {
                  Text() {
                    Span('￥' + item.getPrice())
                      .fontColor('#ffff4d4d')
                      .font({
                        size: 16,
                        weight: 600
                      })
                    Span('.' + item.getDecimals())
                      .fontColor('#ffff4d4d')
                      .font({
                        size: 14,
                        weight: 400
                      })
                  }
                }
                .padding({ left: 4 })
                .width('100%')
                .justifyContent(FlexAlign.Start)

                Line()
                  .width('95%')
                  .height(12)
                  .startPoint([0, 5])
                  .endPoint([165, 5])
                  .stroke('#f1f3f5')
                  .strokeWidth(1)


                Row() {
                  Image(item.getIcon())
                    .height(20)
                    .width(20)
                    .borderRadius('6vp')
                    .margin({ right: 5 })
                  Column() {
                    Text(item.getText())
                      .fontSize(12)
                      .fontColor('#ff000000')
                      .textOverflow({ overflow: TextOverflow.Ellipsis })
                      .maxLines(1)
                    Text("起送￥" + item.getDeliveryFee() + " 免配送费")
                      .maxLines(1)
                      .fontSize(10)
                      .fontColor('#ff8b8c8d')
                  }
                  .width('100%')
                  .justifyContent(FlexAlign.Start)
                  .alignItems(HorizontalAlign.Start)
                }
                .padding({ left: 4, right: 4 })
              }
              .width('100%')
              .height('100%')
              .borderRadius(8)
              .justifyContent(FlexAlign.Start)
              .alignItems(HorizontalAlign.Start)
            }
            .borderRadius(8)
            .backgroundColor(Color.White)
            .width('100%')
            .height(260)
          }, (item: number) => JSON.stringify(item))
        }
        .columnsTemplate('1fr 1fr')
        .columnsGap(8)
        .rowsGap(8)
        .width('100%')
        .scrollBar(BarState.Off)
      }
      .width('92%')
      .borderRadius(8)
      .alignItems(HorizontalAlign.Start)
      .margin({ bottom: 8 })}
    }
    .width('100%')
  }
}

