  static readonly TIMES: string[] =
    ['30分钟', '25分钟', '45分钟'];
  static readonly CONSUMPTIONS: number[] =
    [20, 20, 50];
  static readonly FEES: number[] =
    [2.5, 1.9, 6];
  static readonly FREE: boolean[] =
    [true, false, false];
  static readonly TAGS: string[] =
    ['优享大牌', '品牌', '连锁商超'];

  async getResources(): Promise<void> {
    return new Promise<void>((resolve) => {
      const restaurantArray: ObservedArray<RestaurantModel> = [];
      for (let index = 0; index < RestaurantListModel.TITLES.length;
        index++) {
        restaurantArray.push(new RestaurantModel(
          RestaurantListModel.STORE_IMAGES[index],
          RestaurantListModel.TITLES[index],
          RestaurantListModel.SCORES[index],
          RestaurantListModel.SALES[index],
          RestaurantListModel.DISTANCES[index],
          RestaurantListModel.TIMES[index],
          RestaurantListModel.CONSUMPTIONS[index],
          RestaurantListModel.FEES[index],
          RestaurantListModel.FREE[index],
          RestaurantListModel.TAGS[index]
        ))
      }
      this.lazyDataSource.pushArrayData(restaurantArray);
      resolve();
    });
  }

  getLazyDataSource(): LazyDataSource<RestaurantModel> {
    return this.lazyDataSource;
  }

  getRestaurants(): ObservedArray<RestaurantModel> {
    return this.lazyDataSource.getDataList();
  }

  addRestaurant(restaurant: RestaurantModel): void {
    this.lazyDataSource.pushData(restaurant);
  }

  addRestaurantAt(index: number, restaurant: RestaurantModel): void {
    this.lazyDataSource.addData(index, restaurant);
  }

  deleteRestaurant(index: number): void {
    this.lazyDataSource.deleteData(index);
  }

  clearAll(): void {
    this.lazyDataSource.clear();
  }

  isEmpty(): boolean {
    return this.lazyDataSource.isEmpty();
  }

  getTotalCount(): number {
    return this.lazyDataSource.totalCount();
  }
}

