  @State private viewModel: MultiInfoPersonViewModel = MultiInfoPersonViewModel.getInstance();
  @Consume('appPathStack') appPathStack: NavPathStack;
  @State loadingStatus: LoadingStatus = LoadingStatus.OFF;
  @State lazyDataSource: LazyDataSource<CardSectionPropsModel> = this.viewModel.lazyDataSource;

  jump(pageName:string = 'EmptyPagePathStack'): void {
    this.appPathStack.pushPathByName(pageName, null);
  }

  aboutToAppear() {
    this.loadResources();
  }

  loadResources(): void {
    this.loadingStatus = LoadingStatus.LOADING;
    this.viewModel.getResources().then(() => {
      this.loadingStatus = LoadingStatus.SUCCESS;
    }).catch(() => {
      this.loadingStatus = LoadingStatus.FAILED;
    });
  }

  build() {
    Column() {
      if (this.loadingStatus === LoadingStatus.FAILED) {
        LoadingFailedView(() => this.loadResources())
      }
      if (this.loadingStatus === LoadingStatus.SUCCESS) {
        Row() {
          LazyForEach(this.lazyDataSource,
            (item: CardSectionPropsModel, index: number) => {
              CardSection({
                titleText: item.getText(),
                showArrow: true,
                image: item.getImage(),
                contentTitle: item.getTitle(),
                subtitle: item.getSubTitle(),
                onJump: () => this.jump("MultiInfo_PersonalAttentionDetail"+index.toString())
              })
              if (index >= this.lazyDataSource.totalCount() - 1) {
                Divider()
                  .vertical(true)
                  .height(this.viewModel.getDividerHeight())
                  .color($r('sys.color.comp_divider'))
                  .strokeWidth(1)
              }
            }, (item: CardSectionPropsModel, index: number) => index + JSON.stringify(item))
        }
        .width('92%')
        .height(110)
        .backgroundColor($r('app.color.background_primary'))
        .borderRadius(this.viewModel.getBorderRadius())
        .justifyContent(FlexAlign.SpaceEvenly)
      }
    }
    .width('100%')
    .margin({bottom: 8})
  }
}

