  getUser(): string {
    return this.user;
  }

  getContent(): string {
    return this.content;
  }
}

export class NewsItem {
  private id: string;
  private rank: number;
  private title: string;
  private source: string;
  private commentCount: number;
  private cover: Resource;
  private mediaType: NewsMediaType;
  private hotComment: NewsComment | null;

  constructor(id: string, rank: number, title: string, source: string, commentCount: number, cover: Resource,
    mediaType: NewsMediaType, hotComment: NewsComment | null) {
    this.id = id;
    this.rank = rank;
    this.title = title;
    this.source = source;
    this.commentCount = commentCount;
    this.cover = cover;
    this.mediaType = mediaType;
    this.hotComment = hotComment;
  }

  getId(): string {
    return this.id;
  }

  getRank(): number {
    return this.rank;
  }

  getTitle(): string {
    return this.title;
  }

  getSource(): string {
    return this.source;
  }

  getCommentCount(): number {
    return this.commentCount;
  }

  getCommentCountText(): string {
    if (this.commentCount >= 10000) {
      return `${(this.commentCount / 10000).toFixed(1)}万`;
    }
    return `${this.commentCount}`;
  }

  getCover(): Resource {
    return this.cover;
  }

  getMediaType(): NewsMediaType {
    return this.mediaType;
  }

  hasVideo(): boolean {
    return this.mediaType === NewsMediaType.VIDEO;
  }

  getHotComment(): NewsComment | null {
    return this.hotComment;
  }

  hasHotComment(): boolean {
    return this.hotComment !== null;
  }
}

