  build() {
    Column() {
      Image(this.icon)
        .width(this.iconSize)
        .height(this.iconSize)
        .fillColor(this.iconColor)
        .onClick(() => {
          this.jump()
        })

      Text(this.title)
        .fontColor('#333333')
        .fontSize($r('app.integer.body_text_S'))
        .textOverflow({ overflow: TextOverflow.Ellipsis })
        .maxLines(1)
