  private icon: Resource;
  private text: string;

  constructor(name: string, count: number, icon: Resource,text:string) {
    this.name = name;
    this.count = count;
    this.icon = icon;
    this.text = text;
  }

  getTitle(): string {
    return this.name;
  }

  getCount(): number {
    return this.count;
  }

  getIcon(): Resource {
    return this.icon;
  }

  getText(): string {
    return this.text;
  }
}

