export class FiveScenarioTicketBookingModuleModel {
  private ticketSceneItemList: TicketSceneItem[] = [];
  static readonly TICKET_SCENE_TITLE: string[] = ['火车票', '机票', '酒店', '汽车', '景点', '更多'];
  static readonly TICKET_SCENE_IMAGE: Resource[] =
    [$r("app.media.train"), $r("app.media.air"), $r("app.media.hotel"), $r("app.media.bus"), $r("app.media.hotel"),
      $r("app.media.hotel")];

  constructor() {
    for (let index = 0; index < FiveScenarioTicketBookingModuleModel.TICKET_SCENE_TITLE.length;
      index++) {
      this.ticketSceneItemList.push(new TicketSceneItem(
        FiveScenarioTicketBookingModuleModel.TICKET_SCENE_TITLE[index],
        FiveScenarioTicketBookingModuleModel.TICKET_SCENE_IMAGE[index]));
    }
  }

  getTicketSceneItemList(): TicketSceneItem[] {
    return this.ticketSceneItemList;
  }
}

export class TicketSceneItem {
  /**
   * Text title.
   */
  private title: string;
  /**
   * Image src of the banner.
   */
  private imgSrc: Resource;

  constructor(title: string, imgSrc: Resource) {
    this.imgSrc = imgSrc;
    this.title = title;
  }

  getTitle(): string {
    return this.title;
  }

  getImage(): Resource {
    return this.imgSrc;
  }
}

