import { CommonConstants } from '../common/CommonConstants';
import { OrderMenuData, OrderMenuItemGroupModel, OrderMenuItemModel } from '../viewmodel/OrderMenuModuleModel';

@Component
export struct OrderMenuModule {
  @State selectedIndex: number = 0;
  @State currentHeaderText: string = '';
  private scrollerForList: Scroller = new Scroller();
  private orderMenuTable: OrderMenuItemGroupModel[] = new OrderMenuData().dish_menu_table;

  aboutToAppear() {
    if (this.orderMenuTable.length > 0) {
      this.currentHeaderText = this.orderMenuTable[0].getTitle();
    }
  }

  @Builder
  itemHead(text: string) {
    Text(text)
      .fontSize($r('app.integer.title_text_S'))
      .width(CommonConstants.FULL_PERCENT)
      .padding(10)
      .fontWeight(FontWeight.Bold)
  }

  @Builder
  itemFoot(text: string) {
    Text(text)
      .fontSize($r('app.integer.title_text_S'))
      .width(CommonConstants.FULL_PERCENT)
      .padding(10)
  }

  build() {
    Row() {
      Column() {
        ForEach(this.orderMenuTable, (item: OrderMenuItemGroupModel, index: number) => {
          Row() {
            Divider()
              .vertical(true)
              .height(CommonConstants.FULL_PERCENT)
              .strokeWidth(4)
              .position({ left: 0 })
              .visibility(this.selectedIndex === index ? Visibility.Visible : Visibility.Hidden)
              .color($r('app.color.font_emphasize'))

            Text(item.getTitle())
              .height("53vp")
              .fontColor(this.selectedIndex === index ? $r('app.color.font_emphasize') : $r('app.color.font_primary'))
              .textAlign(TextAlign.Center)
              .fontSize($r('app.integer.subtitle_text_S'))
              .onClick(() => {
                this.selectedIndex = index
                this.scrollerForList.scrollToIndex(index)
              })
          }
          .justifyContent(FlexAlign.Center)
          .height('50vp')
          .width(CommonConstants.FULL_PERCENT)
        })
      }
      .borderRadius({
        topRight: $r('sys.float.corner_radius_level8')
      })
      .width('20%')
      .height(CommonConstants.FULL_PERCENT)
      .justifyContent(FlexAlign.Start)

      Stack({ alignContent: Alignment.TopStart }) {
        Column() {
          List({ scroller: this.scrollerForList }) {
            ForEach(this.orderMenuTable, (item: OrderMenuItemGroupModel, index: number) => {
              ListItemGroup({
                header: this.itemHead(item.getTitle())
              }) {
                ForEach(item.getItems(), (orderMenuItem: OrderMenuItemModel) => {
                  ListItem() {
                    OrderMenuItem({ orderMenuItem: orderMenuItem, showSelectButton: true })
                  }
                })
              }
              .onFocus(() => {
                this.selectedIndex = index
                this.currentHeaderText = item.getTitle()
              })
            })
          }
          .onScrollIndex((firstIndex: number) => {
            this.selectedIndex = firstIndex
            if (firstIndex >= 0 && firstIndex < this.orderMenuTable.length) {
              this.currentHeaderText = this.orderMenuTable[firstIndex].getTitle()
            }
          })
          .width('90%')
          .edgeEffect(EdgeEffect.Spring, {alwaysEnabled: true})
          .scrollBar(BarState.Off)
          .nestedScroll({ scrollForward: NestedScrollMode.PARENT_FIRST, scrollBackward: NestedScrollMode.SELF_FIRST })
        }
        .padding({
          left: "9vp",
          right: "24vp"
        })
        .width('80%')
        .height(CommonConstants.FULL_PERCENT)
        .layoutWeight(1)
        .padding({ top: 5 })


        Text(this.currentHeaderText)
          .fontSize($r('app.integer.title_text_S'))
          .fontWeight(FontWeight.Bold)
          .width('90%')
          .padding(10)
          .backgroundColor($r('app.color.comp_background_primary_trans'))
          .position({ x: "13vp", y: 5 })
      }
    }
    .width(CommonConstants.FULL_PERCENT)
    .padding({
      top: "12vp"
    })
    .borderRadius($r('sys.float.corner_radius_level8'))
    .backgroundColor($r('app.color.comp_background_primary_trans'))
    .margin({ bottom: "10vp" })
  }
}

