export class OrderMenuData {
  static readonly DISH_CATEGORY_LIST: string[] = ['人气Top', '今日特价', '瑞幸早餐', '爆款套餐'];
  static readonly DISH_NAME_LIST: string[][] = [['冰吸生椰拿铁'], ['生椰拿铁', '塞纳莓莓拿铁'], ['葡萄冰萃美式',
    '柠C美式'], ['葡萄冰萃美式', '柠C美式']];
  static readonly DISH_TAG_LIST: string[][] = [['0卡低负担，爱你一万年'], ['0卡低负担，爱你一万年',
    '0卡低负担，爱你一万年'], ['0卡低负担，爱你一万年', '0卡低负担，爱你一万年'],
    ['0卡低负担，爱你一万年', '0卡低负担，爱你一万年']];
  static readonly DISH_DESCRIPTION_LIST: string[][] =
    [['当季热销'], ['女生精选', '当季热销'], ['回头客多', '秋季温暖'], ['回头客多', '秋季温暖']];
  static readonly DISH_PRICE_LIST: string[][] = [['20.8'], ['30.8', '59.9'], ['50.8', '40.8'], ['50.8', '40.8']];
  static readonly DISH_ORIGINAL_PRICE_LIST: string[][] = [['30'], ['40', '80'], ['70', '60'], ['70', '60']];
  static readonly DISH_IMAGE_LIST: Resource[][] = [[$r('app.media.img_goods_logo_1')], [$r('app.media.img_goods_logo_1'),
    $r('app.media.img_goods_logo_1')], [$r('app.media.img_goods_logo_1'), $r('app.media.img_goods_logo_1')],
    [$r('app.media.img_goods_logo_1'), $r('app.media.img_goods_logo_1')]];

  private _dish_menu_table: OrderMenuItemGroupModel[] = [];

  public get dish_menu_table(): OrderMenuItemGroupModel[] {
    return this._dish_menu_table;
  }

  constructor() {
    OrderMenuData.DISH_CATEGORY_LIST.forEach((cat_item, index_cat) => {
      let menu_list: OrderMenuItemModel[] = [];
      OrderMenuData.DISH_NAME_LIST[index_cat].forEach((item, index) => {
        menu_list.push(new OrderMenuItemModel(item,
          OrderMenuData.DISH_TAG_LIST[index_cat][index],
          OrderMenuData.DISH_DESCRIPTION_LIST[index_cat][index], OrderMenuData.DISH_PRICE_LIST[index_cat][index],
          OrderMenuData.DISH_ORIGINAL_PRICE_LIST[index_cat][index], $r('app.media.img_goods_logo_1')))
      })
      this._dish_menu_table.push(new OrderMenuItemGroupModel(cat_item, menu_list));
    })
  }
}

