      }
      .height(24)
      .width('85%')
      .scrollable(ScrollDirection.Horizontal)
      .scrollBar(BarState.Off)
      .margin({ left: 12 , right: 5})

      Button({ type: ButtonType.Circle }) {
        Image($r('sys.media.ohos_ic_public_add'))
          .width('15vp')
          .height('15vp')
      }
      .width('20vp')
      .height('20vp')
      .backgroundColor(Color.White)
    }
    .margin({top: "8vp"})
    .alignItems(VerticalAlign.Center)
  }

  build() {
    Column() {
      if (this.loadingStatus === LoadingStatus.FAILED) {
        LoadingFailedView(() => this.loadResources())
      }

      if (this.loadingStatus === LoadingStatus.SUCCESS) {
        Column() {
          Scroll() {
            Row() {
              ForEach(GiftBoxDataModel.CATEGORIES, (category: string, index: number) => {
                Column() {
                  Stack() {
                    Row()
                      .width('48vp')
                      .height('48vp')
                      .borderRadius(8)
                      .backgroundColor(Color.White)

                    Image(GiftBoxDataModel.TOP_ICONS[index % GiftBoxDataModel.TOP_ICONS.length])
                      .width('32vp')
                      .height('32vp')
                      .objectFit(ImageFit.Contain)
                  }
                  .margin({ bottom: '4vp' })

                  Text(category)
                    .fontSize($r('app.integer.subtitle_text_S'))
                    .fontColor(this.selectedTopIndex === index ? $r('sys.color.font_emphasize') : '#666666')
                    .fontWeight(this.selectedTopIndex === index ? FontWeight.Medium : FontWeight.Regular)
                }
                .margin({ right: '20vp' })
                .onClick(() => {
                  this.selectedTopIndex = index;
                })
              })
            }
          }
          .scrollBar(BarState.Off)
          .scrollable(ScrollDirection.Horizontal)
          .height('88vp')
          .backgroundColor('#F5F5F5')
          .padding({ left: '12vp' })

          Row() {
            Column() {
              LazyForEach(this.lazyDataSource, (group: GiftBoxGroupModel, groupIndex: number) => {
                Row() {
                  if (this.selectedIndex === groupIndex) {
                    Divider()
                      .vertical(true)
                      .strokeWidth(3)
                      .color($r('app.color.background_emphasize'))
                      .height('16vp')
                  }

                  Text(group.getTitle())
                    .fontSize('14fp')
                    .fontColor(this.selectedIndex === groupIndex ? $r('sys.color.font_emphasize') : '#666666')
                    .fontWeight(this.selectedIndex === groupIndex ? FontWeight.Medium : FontWeight.Regular)
                    .width('100%')
                    .textAlign(TextAlign.Center)
                }
                .width('100%')
                .height('44vp')
                .backgroundColor(Color.White)
                .justifyContent(FlexAlign.Center)
                .onClick(() => {
                  this.selectedIndex = groupIndex;
                  this.scrollerForList.scrollToIndex(groupIndex);
                })
              }, (group: GiftBoxGroupModel, index: number) => index.toString() + group.getTitle())
            }
            .width('23%')
            .height('90%')
            .backgroundColor(Color.White)

            Divider()
              .vertical(true)
              .height('100%')
              .color($r('sys.color.comp_divider'))
              .strokeWidth(1.2)
              .opacity(0.6)

            Column() {
              this.SubMenuBar()

              List({ scroller: this.scrollerForList }) {
                LazyForEach(this.lazyDataSource, (group: GiftBoxGroupModel, groupIndex: number) => {
                  ListItemGroup({ header: this.CategoryTitle(group.getTitle()) }) {
                    ForEach(group.getItems(), (item: GiftBoxItemModel, itemIndex: number) => {
                      ListItem() {
                        this.GiftBoxItemComponent(
                          item.getId(),
                          item.getTitle(),
                          item.getDescription(),
                          item.getPrice(),
                          item.getImage(),
                          item.getLabels(),
                          item.getMembershipPrice()
                        )
                      }
                    })
                  }
                }, (group: GiftBoxGroupModel, index: number) => index.toString() + group.getTitle())
              }
              .layoutWeight(1)
              .backgroundColor('#ffffffff')
              .edgeEffect(EdgeEffect.Spring, {alwaysEnabled: true})
              .padding({ left: '12vp', right: '12vp' })
              .onScrollIndex((firstIndex: number) => {
                this.selectedIndex = firstIndex;
              })
              .onClick(() => this.appPathStack.pushPathByName('DetailedPagePathStack', null))
            }
            .width('77%')
            .alignItems(HorizontalAlign.Start)
          }
          .height('100%')
          .justifyContent(FlexAlign.Start)
          .backgroundColor(Color.White)
        }
        .width('100%')
      }
    }
  }
}

