import LazyDataSource from '../util/LazyDataSource';

export class GiftBoxItemModel {
  private id: string;
  private title: string;
  private description: string;
  private price: number;
  private membershipPrice?: number;
  private image: Resource;
  private labels: string[];

  constructor(id: string, title: string, description: string, price: number, image: Resource, labels: string[], membershipPrice?: number) {
    this.id = id;
    this.title = title;
    this.description = description;
    this.price = price;
    this.image = image;
    this.labels = labels;
    this.membershipPrice = membershipPrice;
  }

  getId(): string { return this.id; }
  getTitle(): string { return this.title; }
  getDescription(): string { return this.description; }
  getPrice(): number { return this.price; }
  getMembershipPrice(): number | undefined { return this.membershipPrice; }
  getImage(): Resource { return this.image; }
  getLabels(): string[] { return this.labels; }
}

export class GiftBoxGroupModel {
  private title: string;
  private items: GiftBoxItemModel[];

  constructor(title: string, items: GiftBoxItemModel[]) {
    this.title = title;
    this.items = items;
  }

  getTitle(): string { return this.title; }
  getItems(): GiftBoxItemModel[] { return this.items; }
}

export class GiftBoxDataModel {
  private static instance: GiftBoxDataModel;
  lazyDataSource: LazyDataSource<GiftBoxGroupModel> = new LazyDataSource();

  static readonly CATEGORIES: string[] = ['礼盒/年货', '宝藏年货', '火锅到家', '水果', '蔬菜豆制品'];
  static readonly CATEGORIES_PHOTO: Resource[] = [
    $r('app.media.recommend1'),
    $r('app.media.recommend2'),
    $r('app.media.recommend3'),
    $r('app.media.recommend4'),
    $r('app.media.recommend5')
  ];
  static readonly SIDE_MENU: string[] = [
    '年货上新', '蛇年限定', '零食礼盒', '鲜果礼盒', '家宴主菜',
    '小吃冷盘', '健康滋补', '名酒茗茶', '腊腿干货'
  ];
  static readonly SUB_MENU1: string[] = [
    '推荐', '优选折扣', 'X会员特惠', '新年礼物', '聚划算', '新品打折'
  ];
  static readonly TOP_ICONS: Resource[] = [
    $r('app.media.recommend1'),
    $r('app.media.recommend2'),
    $r('app.media.recommend3'),
    $r('app.media.recommend4'),
    $r('app.media.recommend5')
  ];

  static readonly ITEM_TITLES: string[] = ['智利年厘子 3J 2.5kg 礼盒', '盒马 九珍杏幸干货礼盒 820g', '腊福迎祥腊味礼盒 1.2kg'];

  static readonly ITEM_DESCRIPTIONS: string[] = ['包装随机配送 | 3J大果超值', '九种干货 | 甄选品质', '广式风味 | 六种腊味'];

  static readonly ITEM_PRICES: number[] = [179, 199, 199];

  static readonly ITEM_MEMBERSHIP_PRICES: (number | undefined)[] = [undefined, 168, undefined];

  static readonly ITEM_IMAGES: Resource[] = [$r('app.media.noImage'), $r('app.media.noImage'), $r('app.media.noImage')];

  static readonly ITEM_LABELS: string[][] = [['自营'], ['自营'], ['新品']];

  private _gift_box_groups: GiftBoxGroupModel[] = [];

  public get gift_box_groups(): GiftBoxGroupModel[] {
    return this._gift_box_groups;
  }

  private constructor() {
    GiftBoxDataModel.SIDE_MENU.forEach((menuTitle, ) => {
      let itemList: GiftBoxItemModel[] = [];

      GiftBoxDataModel.ITEM_TITLES.forEach((_, itemIndex) => {
        itemList.push(new GiftBoxItemModel(
          itemIndex.toString(),
          GiftBoxDataModel.ITEM_TITLES[itemIndex % GiftBoxDataModel.ITEM_TITLES.length],
          GiftBoxDataModel.ITEM_DESCRIPTIONS[itemIndex % GiftBoxDataModel.ITEM_DESCRIPTIONS.length],
          GiftBoxDataModel.ITEM_PRICES[itemIndex % GiftBoxDataModel.ITEM_PRICES.length],
          GiftBoxDataModel.ITEM_IMAGES[itemIndex % GiftBoxDataModel.ITEM_IMAGES.length],
          GiftBoxDataModel.ITEM_LABELS[itemIndex % GiftBoxDataModel.ITEM_LABELS.length],
          GiftBoxDataModel.ITEM_MEMBERSHIP_PRICES[itemIndex % GiftBoxDataModel.ITEM_MEMBERSHIP_PRICES.length]
        ));
      });

      this._gift_box_groups.push(new GiftBoxGroupModel(menuTitle, itemList));
    });

    this.lazyDataSource.pushArrayData(this._gift_box_groups);
  }

  public static getInstance(): GiftBoxDataModel {
    if (!GiftBoxDataModel.instance) {
      GiftBoxDataModel.instance = new GiftBoxDataModel();
    }
    return GiftBoxDataModel.instance;
  }

  getResources(): Promise<void> {
    return Promise.resolve();
  }
}

