import { ServiceDataModel, CategoryItem, ServiceItem, CategoryGroup } from '../viewmodel/MultiPage_PureWordListItemModel';

@Component
export struct MultiPage_PureWordListItem {
  @State dataModel: ServiceDataModel = new ServiceDataModel();
  private tabTitles: string[] = ['按主题', '按人生事', '按部门'];
  @State currentHeaderText: string = '';
  private scrollerForList: Scroller = new Scroller();

  aboutToAppear() {
    const groups = this.dataModel.currentCategoryGroups;
    if (groups.length > 0) {
      this.currentHeaderText = groups[0].getTitle();
    }
  }

  build() {
    Column() {

      this.buildTabNavigator()

      if (this.dataModel.currentTabIndex === 2) {
        this.buildDepartmentList()
      } else {
        Row() {
          this.buildCategoryList()

          this.buildServiceList()
        }
        .width('100%')
        .layoutWeight(1)
        .backgroundColor('#F5F7FA')
      }
    }
    .width('100%')
    .height('100%')
    .backgroundColor('#F5F7FA')
  }

  @Builder
  buildTabNavigator() {
    Row() {
      ForEach(this.tabTitles, (title: string, index: number) => {
        Column() {
          Text(title)
            .fontColor($r('app.color.font_secondary'))
            .fontSize($r('app.integer.subtitle_text_M'))
            .fontWeight(this.dataModel.currentTabIndex === index ? FontWeight.Bold : FontWeight.Normal)
            .fontColor(this.dataModel.currentTabIndex === index ? '#333333' : '#666666')

          if (this.dataModel.currentTabIndex === index) {
            Divider()
              .width(24)
              .height(3)
              .borderRadius(1.5)
              .backgroundColor($r('app.color.comp_background_emphasize'))
              .margin({ top: 6 })
          }
        }
        .width('33.3%')
        .height(50)
        .alignItems(HorizontalAlign.Center)
        .justifyContent(FlexAlign.Center)
        .onClick(() => {
          this.dataModel.currentTabIndex = index;
          const groups = this.dataModel.currentCategoryGroups;
          if (groups.length > 0) {
            this.currentHeaderText = groups[0].getTitle();
          }
        })
      })
    }
    .width('100%')
    .height(50)
    .backgroundColor(Color.White)
  }

  @Builder
  buildCategoryList() {
    Column() {
      List() {
        ForEach(this.dataModel.currentCategories, (category: CategoryItem, index: number) => {
          ListItem() {
            Row() {
              Divider()
                .vertical(true)
                .height('100%')
                .strokeWidth(4)
                .position({ left: 0 })
                .visibility(category.isActive ? Visibility.Visible : Visibility.Hidden)
                .color($r('app.color.comp_background_emphasize'))

              Text(category.title)
                .fontSize($r('app.integer.subtitle_text_M'))
                .fontColor(category.isActive ? $r('app.color.comp_background_emphasize') : '#333333')
                .fontWeight(category.isActive ? FontWeight.Medium : FontWeight.Normal)
                .width('100%')
                .textAlign(TextAlign.Center)
            }
            .width('100%')
            .height('100%')
          }
          .height(50)
          .width('100%')
          .onClick(() => {
            this.dataModel.selectedCategoryIndex = index;
            this.scrollerForList.scrollToIndex(index);
          })
        })
      }
      .width('100%')
      .height('100%')
      .scrollBar(BarState.Off)
    }
    .width('28%')
    .height('100%')
    .backgroundColor('#F0F0F0')
  }

  @Builder
  buildServiceList() {
    Stack({ alignContent: Alignment.TopStart }) {
      Column() {
        List({ scroller: this.scrollerForList }) {
          ForEach(this.dataModel.currentCategoryGroups, (group: CategoryGroup, index: number) => {
            ListItemGroup({
              header: this.buildGroupHeader(group.getTitle())
            }) {
              ForEach(group.getItems(), (service: ServiceItem) => {
                ListItem() {
                  this.buildServiceItem(service)

                }
              })
            }
            .onFocus(() => {
              this.dataModel.selectedCategoryIndex = index;
              this.currentHeaderText = group.getTitle();
            })
          })
        }
        .onScrollIndex((firstIndex: number) => {
          this.dataModel.selectedCategoryIndex = firstIndex;
          if (firstIndex >= 0 && firstIndex < this.dataModel.currentCategoryGroups.length) {
            this.currentHeaderText = this.dataModel.currentCategoryGroups[firstIndex].getTitle();
          }
        })
        .width('100%')
        .edgeEffect(EdgeEffect.None)
        .scrollBar(BarState.Off)
      }
      .width('100%')
      .height('100%')


      Text(this.currentHeaderText)
        .fontColor($r('app.color.font_primary'))
        .fontSize($r('app.integer.subtitle_text_M'))
        .fontWeight(FontWeight.Medium)
        .width('100%')
        .padding({ left: 12, top: 12, bottom: 12 })
        .backgroundColor(Color.White)
        .position({ x: 0, y: 0 })
    }
    .width('72%')
    .height('100%')
    .backgroundColor('#F5F7FA')
  }

  @Builder
  buildDepartmentList() {
    Column() {
      List() {
        ForEach(this.dataModel.currentCategoryGroups, (department: CategoryGroup) => {
          ListItem() {
            Column() {
              Text(department.getTitle())
                .fontColor($r('app.color.font_primary'))
                .fontSize($r('app.integer.subtitle_text_M'))
                .fontWeight(FontWeight.Bold)
                .width('100%')
                .padding({ left: 12, right: 16, top: 12, bottom: 12 })
                .backgroundColor(Color.White)
                .borderRadius({ topLeft: 4, topRight: 4 })

              ForEach(department.getItems(), (service: ServiceItem) => {
                this.buildServiceItem(service)
              })
            }
            .width('100%')
            .borderRadius(4)
            .margin({ bottom: 12 })
          }
        })
      }
      .width('100%')
      .layoutWeight(1)
      .padding({ left: 16, right: 16, top: 12 })
      .backgroundColor('#F5F7FA')
      .scrollBar(BarState.Off)
    }
    .width('100%')
    .height('100%')
    .backgroundColor('#F5F7FA')
  }

  @Builder
  buildServiceItem(service: ServiceItem) {
    Row() {
      Column() {
        Row() {
          Text(service.title)
            .fontColor($r('app.color.font_secondary'))
            .fontSize($r('app.integer.body_text_M'))
            .fontWeight(FontWeight.Medium)
            .layoutWeight(1)

          if (service.isCommon) {
            Text('常用')
              .fontSize($r('app.integer.body_text_S'))
              .fontColor(Color.White)
              .backgroundColor($r('app.color.comp_background_emphasize'))
              .borderRadius($r('sys.float.corner_radius_level4'))
              .padding({ left: 4, right: 4, top: 2, bottom: 2 })
          }
        }
        .width('100%')
        .justifyContent(FlexAlign.SpaceBetween)
        .alignItems(VerticalAlign.Center)

      }
      .layoutWeight(1)

      Image($r('app.media.dot_grid_1x2'))
        .width(16)
        .height(16)
        .margin({ left: 8 })
    }
    .width('100%')
    .padding({ left: 12, right: 16, top: 14, bottom: 14 })
    .backgroundColor(Color.White)
    .margin({ bottom: 1 })
  }

  @Builder
  buildGroupHeader(title: string) {
    Text(title)
      .fontColor($r('app.color.font_primary'))
      .fontSize($r('app.integer.subtitle_text_M'))
      .fontWeight(FontWeight.Bold)
      .width('100%')
      .padding({ left: 12, top: 12, bottom: 12 })
  }
}

