    for (let i = 0; i < this._educationServiceIds.length; i++) {
      let serviceItem = new ServiceItem(
        this._educationServiceIds[i],
        this._educationServiceTitles[i],
        this._educationServiceCommons[i]
      );
      educationServiceItems.push(serviceItem);
    }
    this._themeGroups.push(new CategoryGroup('2', this._themeCategoryTitles[2], educationServiceItems));
