      );
      envServiceItems.push(serviceItem);
    }
    this._departmentGroups.push(new CategoryGroup('0', this._deptGroupTitles[0], envServiceItems));

    let eduServiceItems: Array<ServiceItem> = [];
    for (let i = 0; i < this._eduServiceIds.length; i++) {
      let serviceItem = new ServiceItem(
        this._eduServiceIds[i],
        this._eduServiceTitles[i],
