  get currentTabIndex(): number {
    return this._currentTabIndex;
  }

  set currentTabIndex(index: number) {
    this._currentTabIndex = index;
    this._selectedCategoryIndex = 0;
  }

  get currentCategories(): Array<CategoryItem> {
    let categories: Array<CategoryItem> = [];

    let ids: string[] = [];
    let titles: string[] = [];
    let actives: boolean[] = [];

    switch (this._currentTabIndex) {
      case 0:
        ids = this._themeCategoryIds;
        titles = this._themeCategoryTitles;
        actives = this._themeCategoryActives;
        break;
      case 1:
        ids = this._lifeEventCategoryIds;
        titles = this._lifeEventCategoryTitles;
        actives = this._lifeEventCategoryActives;
        break;
      case 2:
        ids = this._departmentCategoryIds;
        titles = this._departmentCategoryTitles;
        actives = this._departmentCategoryActives;
        break;
      default:
        ids = this._themeCategoryIds;
        titles = this._themeCategoryTitles;
        actives = this._themeCategoryActives;
    }

    for (let i = 0; i < ids.length; i++) {
      categories.push(new CategoryItem(ids[i], titles[i], actives[i]));
    }

    return categories;
  }

  get currentCategoryGroups(): Array<CategoryGroup> {
    switch (this._currentTabIndex) {
      case 0:
        return this._themeGroups;
      case 1:
        return this._lifeEventGroups;
      case 2:
        return this._departmentGroups;
      default:
        return this._themeGroups;
    }
  }

  get selectedCategoryIndex(): number {
    return this._selectedCategoryIndex;
  }

  set selectedCategoryIndex(index: number) {
    this._selectedCategoryIndex = index;

    let categories = this.currentCategories;

    let activeArray: boolean[] = [];
    switch (this._currentTabIndex) {
      case 0:
        activeArray = this._themeCategoryActives;
        break;
      case 1:
        activeArray = this._lifeEventCategoryActives;
        break;
      case 2:
        activeArray = this._departmentCategoryActives;
        break;
    }

    for (let i = 0; i < activeArray.length; i++) {
      activeArray[i] = (i === index);
    }

    categories.forEach((category, idx) => {
      category.isActive = (idx === index);
    });
  }

  setCurrentCategory(categoryId: string): void {
    const index = this.currentCategories.findIndex(item => item.id === categoryId);
    if (index !== -1) {
      this.selectedCategoryIndex = index;
    }
  }
}

