  AUDIO = '声音',
  SPECIAL = '专辑'
}

export class PlaylistItem {
  private id: string;
  private title: string;
  private cover: Resource;
  private type: PlaylistType;

  constructor(id: string, title: string, cover: Resource, type: PlaylistType) {
    this.id = id;
    this.title = title;
    this.cover = cover;
    this.type = type;
  }

  getId(): string {
    return this.id;
  }

  getTitle(): string {
    return this.title;
  }



  getCover(): Resource {
    return this.cover;
  }

  getType(): PlaylistType {
    return this.type;
  }
}

export class PlaylistRecommendModel {
  private playlists: PlaylistItem[] = [];
  private title: string = '听单';

  static readonly PLAYLIST_IDS: string[] = ['1', '2', '3', '4', '5'];

  static readonly PLAYLIST_TITLES: string[] = [
    '小长假:小摳怡情的9大电影清单',
    '圣诞派对 | 孩子喜爱的圣诞儿歌集锦，快收藏！',
    '给小孩的一封信：我是勇敢的胆小鬼',
    '童心向党，经典传诵',
    '315维权'
  ];


  static readonly PLAYLIST_COVERS: Resource[] = [
    $r('app.media.noImage'),
    $r('app.media.noImage'),
    $r('app.media.noImage'),
    $r('app.media.noImage'),
    $r('app.media.noImage')
  ];

  static readonly PLAYLIST_TYPES: PlaylistType[] = [
    PlaylistType.AUDIO,
    PlaylistType.AUDIO,
    PlaylistType.AUDIO,
    PlaylistType.SPECIAL,
    PlaylistType.AUDIO
  ];

  constructor() {
    this.initPlaylists();
  }

  private initPlaylists(): void {
    for (let i = 0; i < PlaylistRecommendModel.PLAYLIST_IDS.length; i++) {
      this.playlists.push(new PlaylistItem(
        PlaylistRecommendModel.PLAYLIST_IDS[i],
        PlaylistRecommendModel.PLAYLIST_TITLES[i],
        PlaylistRecommendModel.PLAYLIST_COVERS[i],
        PlaylistRecommendModel.PLAYLIST_TYPES[i]
      ));
    }
  }

  getTitle(): string {
    return this.title;
  }

  getPlaylists(): PlaylistItem[] {
    return this.playlists;
  }
}

