import {
  News_SwiperAudioBookListModel,
  AudioBookListModel
} from '../viewmodel/News_SwiperAudioBookListModel';
import { LoadingStatus } from '../common/CommonEnums';
import { LoadingFailedView } from '../view/LoadingFailedView';
import LazyDataSource from '../util/LazyDataSource';

@Component
export struct News_SwiperAudioBookList {
  @State itemModel: News_SwiperAudioBookListModel = News_SwiperAudioBookListModel.getInstance();
  @State loadingStatus: LoadingStatus = LoadingStatus.OFF;
  @State lazyDataSource: LazyDataSource<Array<AudioBookListModel>> = this.itemModel.lazyDataSource;
  @State moduleTitle: string = "历史";
  @State moduleRedirectContent: string = "换一换";

  aboutToAppear() {
    this.loadResources();
  }

  loadResources(): void {
    this.loadingStatus = LoadingStatus.LOADING;
    this.itemModel.getResources().then(() => {
      this.loadingStatus = LoadingStatus.SUCCESS;
    }).catch(() => {
      this.loadingStatus = LoadingStatus.FAILED;
    });
  }

  build() {
    Column() {
      if (this.loadingStatus === LoadingStatus.FAILED) {
        LoadingFailedView(() => this.loadResources())
      }
      if (this.loadingStatus === LoadingStatus.SUCCESS) {
        Row() {
          Text(this.moduleTitle)
            .fontSize(14).fontWeight(FontWeight.Medium).layoutWeight(1)
          Text(this.moduleRedirectContent)
            .fontSize(12).fontColor($r('sys.color.font_secondary'))
        }
        .margin(8)
        .height(12)
        .justifyContent(FlexAlign.SpaceBetween)
        Swiper() {
          LazyForEach(this.lazyDataSource, (itemArray: Array<AudioBookListModel>, index: number) => {
            List() {
              ForEach(itemArray, (item: AudioBookListModel)=> {
                VideoPostItem({
                  cover: item.getImage(),
                  title: item.getTitle(),
                  subtitle: item.getSubtitle(),
                  playCount: item.getPlayCount(),
                  tag: item.getTag(),
                })
              })
            }
          }, (itemArray:Array<AudioBookListModel>, index: number) => index.toString())
        }
        .width('100%')
        .height(260)
        .indicator(
          new DotIndicator()
            .bottom(6)
            .selectedItemWidth(7)
            .selectedItemHeight(7)
            .selectedColor(Color.Gray)
        )
      }
    }
    .width('100%')
    .height(280)
    .backgroundColor('#ffffffff')
    .margin({bottom: 8})
  }
}

@Component
export struct VideoPostItem {
  @State title: string = '';
  @State subtitle: string = '';
  @State cover: Resource = $r('app.media.backgroundImg2');
  @State icon: Resource = $r('sys.media.ohos_ic_public_device_earphone_filled');
  @State playCount: string = '';
  @State tag: string = '';

  build() {
    Row() {
      Image(this.cover)
        .height(70)
        .width(70)
        .borderRadius(8)
        .margin(8)
      Column() {
        Text(this.title)
          .fontSize(16)
          .fontWeight(FontWeight.Medium)
          .margin({bottom: 6})
          .maxLines(1)
          .textOverflow({overflow: TextOverflow.Ellipsis})
        Text(this.subtitle)
          .fontSize(12)
          .fontColor($r('sys.color.font_secondary'))
          .margin({bottom: 6})
          .maxLines(1)
          .textOverflow({overflow: TextOverflow.Ellipsis})
        Row() {
          Image(this.icon)
            .height(12)
            .width(12)
            .fillColor($r('sys.color.font_tertiary'))
            .padding({right: 4})
            .objectFit(ImageFit.Contain)
          Text(this.playCount)
            .fontSize(10)
            .fontColor($r('sys.color.font_tertiary'))
            .padding({right: 4})
          if (this.tag) {
            Text(this.tag)
              .fontSize(8)
              .fontColor("#ffe95050")
              .backgroundColor("#ffe78e8e")
              .padding({left: 4, right: 4, top: 2, bottom: 2})
              .borderRadius(4)
          }
        }
        .width('80%')
      }
      .layoutWeight(1)
      .alignItems(HorizontalAlign.Start)
    }
    .width('92%')
    .height(80)
