  private static instance: News_SwiperAudioBookListModel;
  lazyDataSource: LazyDataSource<AudioBookListModel[]> = new LazyDataSource();
  static readonly IMAGES: Resource[] = [
    $r('app.media.backgroundImg2'),
    $r('app.media.backgroundImg2'),
    $r('app.media.backgroundImg2'),
    $r('app.media.backgroundImg2'),
    $r('app.media.backgroundImg2'),
    $r('app.media.backgroundImg2')
  ];
  static readonly TITLES: string[] = [
    '中国历史未解之谜（听更多历史，请点击）',
    '细讲中国历史 | 从夏到清，完整展现',
    '重说中国近代史',
    '秦始皇全传',
    '历史未解之谜全纪录',
    '民国人物列传'
  ];
  static readonly SUBTITLES: string[] = [
    '磁性声音讲述有趣历史',
    '国家新闻出版广电总局首届向全国推荐的优秀作品',
    '从鸦片战争到五四运动，漫长的八十年里，中国经历了深刻变革。',
    '专辑简介：秦始皇终结了春秋战国的历史，——',
    '除非地球毁灭，每天至少更一集，刮风下雨不停更',
    '各位听众朋友，抖音搜索【藤卷总之无稽之谈】'
  ];
  static readonly PLAY_ICON: Resource[] = [
    $r('sys.media.ohos_ic_public_device_earphone_filled'),
    $r('sys.media.ohos_ic_public_device_earphone_filled'),
    $r('sys.media.ohos_ic_public_device_earphone_filled'),
    $r('sys.media.ohos_ic_public_device_earphone_filled'),
    $r('sys.media.ohos_ic_public_device_earphone_filled'),
    $r('sys.media.ohos_ic_public_device_earphone_filled')
  ];
  static readonly PLAY_COUNTS: string[] = [
    '999万+',
    '999万+',
    '999万+',
    '999万+',
    '999万+',
    '999万+'
  ];
  static readonly TAGS: string[] = [
    '热搜榜NO.17',
    '',
    '',
    '',
    '',
    ''
  ];

  constructor() {
  }

  public static getInstance(): News_SwiperAudioBookListModel {
    if (!News_SwiperAudioBookListModel.instance) {
      News_SwiperAudioBookListModel.instance = new News_SwiperAudioBookListModel();
    }
    return News_SwiperAudioBookListModel.instance;
  }

  getResources(): Promise<void> {
    return new Promise((resolve: Function, reject: Function) => {
      try {
        const modelList: Array<Array<AudioBookListModel>> = [];
        for (let index = 0; index < News_SwiperAudioBookListModel.TITLES.length; index++) {
          if (index % 3 == 0) {
            modelList.push([]);
          }
          modelList[~~(index / 3)].push(new AudioBookListModel(
            News_SwiperAudioBookListModel.IMAGES[index],
            News_SwiperAudioBookListModel.TITLES[index],
            News_SwiperAudioBookListModel.SUBTITLES[index],
            News_SwiperAudioBookListModel.PLAY_ICON[index],
            News_SwiperAudioBookListModel.PLAY_COUNTS[index],
            News_SwiperAudioBookListModel.TAGS[index]
          ));
        }
        this.lazyDataSource.pushArrayData(modelList);
        resolve();
      } catch (error) {
        reject(error);
      }
    });
  }
}

