import { CarRankModel, HotRankModel, HotRankModels, RankItemModel, RankModel } from '../viewmodel/News_SwiperHorizontalCarRankModel';

@Component
export struct News_SwiperHorizontalCarRank {
  @State currentIndex: number = 0;
  @State originalModels: HotRankModels[] = [
    new HotRankModels('热议', CarRankModel.getInstance()),
    new HotRankModels('热榜', HotRankModel.getInstance())
  ];
  @State rankModels: HotRankModels[] = [];

  @Consume('appPathStack') appPathStack: NavPathStack;

  listController: ListScroller = new ListScroller();

  private originalLength: number = 0;

  aboutToAppear() {
    this.originalLength = this.originalModels.length;

    this.rankModels = [
      ...this.originalModels,
      ...this.originalModels,
      ...this.originalModels
    ];


    this.originalModels.forEach(model => {
      model.model.getResources();
    });

    setTimeout(() => {
      this.listController.scrollToIndex(this.originalLength);
    }, 100);
  }

  private getOriginalIndex(index: number): number {
    return index % this.originalLength;
  }

  private checkScrollPosition(index: number) {
    if (index < this.originalLength) {
      setTimeout(() => {
        this.listController.scrollToIndex(index + this.originalLength, false);
      }, 100);
    }

    else if (index >= this.originalLength * 2) {
      setTimeout(() => {
        this.listController.scrollToIndex(index - this.originalLength, false);
      }, 100);
    }
  }

  build() {
    Column() {
      Row(){
        Image($r('app.media.startIcon'))
          .width(24)
          .height(24)
          .objectFit(ImageFit.Contain)

        Row() {
          ForEach(this.originalModels, (item: HotRankModels, index: number) => {
            Column() {
              Text(item.title)
                .fontSize(16)
                .fontWeight(this.getOriginalIndex(this.currentIndex) === index ? FontWeight.Bold : FontWeight.Normal)
                .fontColor(this.getOriginalIndex(this.currentIndex) === index ? '#FF5722' : '#333333')
                .padding(4)

              // 底部白条（仅在当前选中项显示）
              if (this.getOriginalIndex(this.currentIndex) === index) {
                Divider()
                  .width(24)
                  .height(5)
                  .color($r('sys.color.comp_divider'))
              }
            }
            .onClick(() => {
              // 计算中间段的对应索引
              const targetIndex = index + this.originalLength;
              this.currentIndex = targetIndex;
              // 点击导航时滚动列表到相应位置
              this.listController.scrollToIndex(targetIndex);
            })
          })
        }
        .width('100%')
        .justifyContent(FlexAlign.Start)
        .padding({ left: 8 })
      }
      .width('92%')

      List({ space: 8, initialIndex: this.originalLength, scroller: this.listController }) {
        ForEach(this.rankModels, (item: HotRankModels, index: number) => {
          ListItem() {
            RankListContent({
              rankModel: item.model,
              title: item.title
            })
          }
          .width('90%')
        })
      }
      .listDirection(Axis.Horizontal)
      .width('100%')
      .sticky(StickyStyle.None)
      .padding({ left: '5%', right: 0 })
      .scrollBar(BarState.Off)
      .edgeEffect(EdgeEffect.Spring)
      .onScrollStop(() => {
        this.checkScrollPosition(this.currentIndex);
      })
      .onScrollIndex((firstIndex: number) => {
        if (firstIndex != this.currentIndex) {
          this.currentIndex = firstIndex;
        }
      })
    }
    .width('100%')
  }
}

@Component
struct RankListContent {
  rankModel: RankModel = new RankModel();
  title: string = '';
  @Consume('appPathStack') appPathStack: NavPathStack;

  jump(pageName:string = 'EmptyPagePathStack'): void {
    this.appPathStack.pushPathByName(pageName, null);
  }

  build() {
    Column() {
      List() {
        LazyForEach(this.rankModel.lazyDataSource, (item: RankItemModel, index: number) => {
          ListItem() {
            RankListItem({
              rankNumber: item.getRankNumber(),
              title: item.getTitle(),
              isHot: item.getIsHot()
            })
          }
          .onClick(() => {
            this.jump("RankListContentDetail"+index.toString())
          })
        })

        ListItem() {
          Row() {
            Text('查看完整榜单')
              .fontSize(12)
              .fontColor('#666666')

            Image($r('app.media.ic_right_arrow_filled'))
              .width(10)
              .height(10)
              .margin({ left: 4 })
          }
          .width('100%')
          .justifyContent(FlexAlign.Center)
          .padding(4)
          .onClick(() => {
            this.jump()
          })
        }
      }
      .backgroundColor('#FFFFFF')
      .borderRadius(12)
      .width('100%')
      .padding(8)
      .margin({ top: 8 })
    }
    .width('100%')
    .alignItems(HorizontalAlign.Center)
    .margin({ bottom: 8 })
  }
}

@Component
struct RankListItem {
  rankNumber: number = 1;
  title: string = '';
  isHot: boolean = false;

  build() {
    Row() {
      Text(this.rankNumber.toString())
        .fontSize(16)
        .fontWeight(FontWeight.Bold)
        .fontColor(this.getRankColor())
        .width(30)

      Text(this.title)
        .fontSize(14)
        .fontColor('#333333')
        .flexGrow(1)
        .textOverflow({ overflow: TextOverflow.Ellipsis })
        .maxLines(1)

      if(this.isHot) {
        Text('热')
          .fontSize(10)
          .fontColor('#FFFFFF')
          .backgroundColor('#FF5722')
          .borderRadius(4)
          .padding(2)
          .textAlign(TextAlign.Center)
      }
    }
    .width('100%')
    .padding({ top: 8, bottom: 8 })
    .justifyContent(FlexAlign.SpaceBetween)
    .alignItems(VerticalAlign.Center)
  }

  private getRankColor(): string {
    if(this.rankNumber === 1) return '#FF5722';
    if(this.rankNumber === 2) return '#FF9800';
    if(this.rankNumber === 3) return '#FFC107';
    return '#999999';
  }
}

