  CartItem(item: ShopItem) {
    Flex({ direction: FlexDirection.Row, alignItems: ItemAlign.Center }) {
      Checkbox({ name: 'checkbox1', group: 'checkboxGroup' })
        .unselectedColor('#ffb0b0b0')
        .selectedColor(Color.Red)
        .shape(CheckBoxShape.CIRCLE)
        .onChange((value: boolean) => {
          console.info('Checkbox1 change is' + value)
        })

      Row() {
        Image(item.getImg())
          .height(70)
          .width(70)
          .borderRadius(5)
          .colorFilter(this.ColorFilterMatrix)
          .margin({ left: 4 })

        Flex({ direction: FlexDirection.Column, justifyContent: FlexAlign.SpaceAround }) {
          Text(item.getText())
            .fontSize('14fp')
            .margin({ bottom: '8vp' })
            .textOverflow({ overflow: TextOverflow.Ellipsis })
            .maxLines(2)
            .width('100%')
          Text('￥' + item.getPrice())
        }
        .padding(8)
        .layoutWeight(1)
      }
    }
    .width('100%')
    .height('112vp')
  }

  build() {
    Column() {
      if (this.loadingStatus === LoadingStatus.FAILED) {
        LoadingFailedView(() => this.loadResources())
      }
      if (this.loadingStatus === LoadingStatus.SUCCESS) {
        Flex({ direction: FlexDirection.Column }) {
          ModuleTitleComponent({
				title: this.moduleTitle,
				moduleRedirectContent: this.moduleRedirectContent,
				onJump: () => {
				  this.jump()
				}})

          List({ space: 8 }) {
            LazyForEach(this.lazyDataSource, (item: ShopItem[], index: number): void => {
              ListItem() {
                Column() {
                  Row() {
                    this.Settle()
                    Text(this.shopCartModel.getNames()[index] + ' >')
                  }.margin({ top: 5 })
                  .padding({
                    left: '10vp',
                    right: '10vp'
                  })
                  .justifyContent(FlexAlign.Start)
                  .width(330)

                  Column() {
                    List() {
                      ForEach(item, (item1: ShopItem, index: number) => {
                        ListItem() {
                          this.CartItem(item1)
                        }
